consumption.cssSetup:
Import tokens CSS at your app entry point: import '@ds-mo/tokens/css';
This provides all var(--color-*), var(--dimension-*), var(--effect-*), and var(--typography-*) custom properties.
For dark mode, set data-theme="dark" on <html>.

files.content:
.tab {
  display: flex;
  align-items: center;
  justify-content: center;
  padding: var(--dimension-space-075);
  background-color: transparent;
  border: none;
  border-radius: var(--dimension-radius-075);
  cursor: pointer;
  user-select: none;
  color: var(--color-foreground-secondary);
  position: relative;
  will-change: color;
  transition: color var(--effect-motion-short-2);
  flex-shrink: 0;
  height: var(--dimension-size-400);
  box-sizing: border-box;
}

.tab::before {
  content: '';
  position: absolute;
  inset: 0;
  background-color: transparent;
  border-radius: var(--dimension-radius-075);
  transition: var(--effect-transition-interaction-background-short-2);
  pointer-events: none;
  z-index: 0;
}

.tab > * { position: relative; z-index: 1; }

.tab:hover::before { background-color: var(--color-interaction-hover); }
.tab:active::before { background-color: var(--color-interaction-pressed); transition: var(--effect-transition-interaction-background-instant); }

.tabSelected { color: var(--color-foreground-primary); }

import React, { forwardRef } from 'react';
import { cn } from '@/utils/cn';
import { Text } from '@/components/Text';
import styles from './Tab.module.css';

export interface TabProps {
  id?: string;
  label: string;
  isSelected?: boolean;
  onClick?: () => void;
  className?: string;
}

export const Tab = forwardRef<HTMLButtonElement, TabProps>(
  ({ id, label, isSelected = false, onClick, className }, ref) => (
    <button
      ref={ref}
      id={id}
      className={cn(styles.tab, isSelected && styles.tabSelected, className)}
      onClick={onClick}
      type="button"
      aria-selected={isSelected}
      role="tab"
    >
      <Text variant={isSelected ? 'text-body-medium-emphasis' : 'text-body-medium'} as="span">
        {label}
      </Text>
    </button>
  )
);

Tab.displayName = 'Tab';
